    private static long countInversions(ArrayList<Long> arr) {
        if (arr.size() <= 1) {
            return 0;
        }

        int mid = arr.size() / 2;
        ArrayList<Long> left = new ArrayList<>(arr.subList(0, mid));
        ArrayList<Long> right = new ArrayList<>(arr.subList(mid, arr.size()));

        long leftInversions = countInversions(left);
        long rightInversions = countInversions(right);
        long mergeInversions = mergeAndCount(arr, left, right);

        return leftInversions + rightInversions + mergeInversions;
    }

    private static long mergeAndCount(ArrayList<Long> arr, ArrayList<Long> left, ArrayList<Long> right) {
        int i = 0, j = 0, k = 0;
        long inversions = 0;

        while (i < left.size() && j < right.size()) {
            if (left.get(i) <= right.get(j)) {
                arr.set(k++, left.get(i++));
            } else {
                arr.set(k++, right.get(j++));
                inversions += left.size() - i;
            }
        }

        while (i < left.size()) {
            arr.set(k++, left.get(i++));
        }

        while (j < right.size()) {
            arr.set(k++, right.get(j++));
        }

        return inversions;
    }

